+// ===========================================================================
+// Agent: tool_not_found in multi-tool batch + successful tool in same batch
+// ===========================================================================
+
+/// Provider that emits a batch of tool calls, some pointing to real tools,
+/// some pointing to nonexistent tools. Verifies mixed success/error results.
+#[derive(Debug)]
+struct MixedToolCallProvider {
+    stream_calls: AtomicUsize,
+    good_tool_name: String,
+    bad_tool_name: String,
+    good_tool_path: String,
+}
+
+#[async_trait]
+#[allow(clippy::unnecessary_literal_bound)]
+impl Provider for MixedToolCallProvider {
+    fn name(&self) -> &str {
+        "mixed-tool-provider"
+    }
+
+    fn api(&self) -> &str {
+        "mixed-tool-api"
+    }
+
+    fn model_id(&self) -> &str {
+        "mixed-tool-model"
+    }
+
+    async fn stream(
+        &self,
+        context: &Context,
+        _options: &StreamOptions,
+    ) -> Result<Pin<Box<dyn Stream<Item = Result<StreamEvent>> + Send>>> {
+        let call_index = self.stream_calls.fetch_add(1, Ordering::SeqCst);
+
+        if call_index == 0 {
+            // First call: emit a batch with one good tool call + one bad tool call
+            let msg = AssistantMessage {
+                content: vec![
+                    ContentBlock::ToolCall(ToolCall {
+                        id: "good-1".to_string(),
+                        name: self.good_tool_name.clone(),
+                        arguments: json!({ "path": self.good_tool_path }),
+                        thought_signature: None,
+                    }),
+                    ContentBlock::ToolCall(ToolCall {
+                        id: "bad-1".to_string(),
+                        name: self.bad_tool_name.clone(),
+                        arguments: json!({}),
+                        thought_signature: None,
+                    }),
+                ],
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage {
+                    total_tokens: 30,
+                    output: 30,
+                    ..Usage::default()
+                },
+                stop_reason: StopReason::ToolUse,
+                error_message: None,
+                timestamp: 0,
+            };
+            let partial = AssistantMessage {
+                content: Vec::new(),
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage::default(),
+                stop_reason: StopReason::Stop,
+                error_message: None,
+                timestamp: 0,
+            };
+            return Ok(Box::pin(EventSequence {
+                events: vec![
+                    Some(StreamEvent::Start { partial }),
+                    Some(StreamEvent::Done {
+                        reason: StopReason::ToolUse,
+                        message: msg,
+                    }),
+                ],
+                index: 0,
+            }));
+        }
+
+        if call_index == 1 {
+            // Verify tool results came through
+            let results: Vec<&ToolResultMessage> = context
+                .messages
+                .iter()
+                .filter_map(|m| match m {
+                    Message::ToolResult(r) => Some(r),
+                    _ => None,
+                })
+                .collect();
+
+            let good_result = results.iter().find(|r| r.tool_call_id == "good-1");
+            let bad_result = results.iter().find(|r| r.tool_call_id == "bad-1");
+
+            let mut verification = Vec::new();
+
+            if let Some(good) = good_result {
+                verification.push(format!(
+                    "good_tool: is_error={}, has_content={}",
+                    good.is_error,
+                    !good.content.is_empty()
+                ));
+            }
+            if let Some(bad) = bad_result {
+                verification.push(format!(
+                    "bad_tool: is_error={}, text={}",
+                    bad.is_error,
+                    tool_result_text(bad)
+                ));
+            }
+
+            let msg = AssistantMessage {
+                content: vec![ContentBlock::Text(TextContent::new(
+                    verification.join("; "),
+                ))],
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage {
+                    total_tokens: 20,
+                    output: 20,
+                    ..Usage::default()
+                },
+                stop_reason: StopReason::Stop,
+                error_message: None,
+                timestamp: 0,
+            };
+            let partial = AssistantMessage {
+                content: Vec::new(),
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage::default(),
+                stop_reason: StopReason::Stop,
+                error_message: None,
+                timestamp: 0,
+            };
+            return Ok(Box::pin(EventSequence {
+                events: vec![
+                    Some(StreamEvent::Start { partial }),
+                    Some(StreamEvent::Done {
+                        reason: StopReason::Stop,
+                        message: msg,
+                    }),
+                ],
+                index: 0,
+            }));
+        }
+        Err(Error::api("unexpected provider call"))
+    }
+}
+
+/// Provider that emits a tool call to a tool that will return an Err().
+/// This exercises agent.rs:1349-1356 (tool execution error wrapping).
+#[derive(Debug)]
+struct ErrorToolProvider {
+    stream_calls: AtomicUsize,
+}
+
+#[async_trait]
+#[allow(clippy::unnecessary_literal_bound)]
+impl Provider for ErrorToolProvider {
+    fn name(&self) -> &str {
+        "error-tool-provider"
+    }
+
+    fn api(&self) -> &str {
+        "error-tool-api"
+    }
+
+    fn model_id(&self) -> &str {
+        "error-tool-model"
+    }
+
+    async fn stream(
+        &self,
+        context: &Context,
+        _options: &StreamOptions,
+    ) -> Result<Pin<Box<dyn Stream<Item = Result<StreamEvent>> + Send>>> {
+        let call_index = self.stream_calls.fetch_add(1, Ordering::SeqCst);
+
+        if call_index == 0 {
+            // Call a tool that will throw an error during execution
+            let msg = AssistantMessage {
+                content: vec![ContentBlock::ToolCall(ToolCall {
+                    id: "bash-err-1".to_string(),
+                    name: "bash".to_string(),
+                    arguments: json!({
+                        "command": "echo hello",
+                        "timeout": -1  // Invalid; bash tool interprets negative as error
+                    }),
+                    thought_signature: None,
+                })],
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage {
+                    total_tokens: 25,
+                    output: 25,
+                    ..Usage::default()
+                },
+                stop_reason: StopReason::ToolUse,
+                error_message: None,
+                timestamp: 0,
+            };
+            let partial = AssistantMessage {
+                content: Vec::new(),
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage::default(),
+                stop_reason: StopReason::Stop,
+                error_message: None,
+                timestamp: 0,
+            };
+            return Ok(Box::pin(EventSequence {
+                events: vec![
+                    Some(StreamEvent::Start { partial }),
+                    Some(StreamEvent::Done {
+                        reason: StopReason::ToolUse,
+                        message: msg,
+                    }),
+                ],
+                index: 0,
+            }));
+        }
+
+        // Second call: check if the error tool result was properly wrapped
+        if call_index == 1 {
+            let results: Vec<&ToolResultMessage> = context
+                .messages
+                .iter()
+                .filter_map(|m| match m {
+                    Message::ToolResult(r) => Some(r),
+                    _ => None,
+                })
+                .collect();
+
+            let msg_text = if let Some(result) = results.iter().find(|r| r.tool_call_id == "bash-err-1") {
+                format!(
+                    "bash_result: is_error={}, text={}",
+                    result.is_error,
+                    tool_result_text(result)
+                )
+            } else {
+                "bash_result: MISSING".to_string()
+            };
+
+            let msg = AssistantMessage {
+                content: vec![ContentBlock::Text(TextContent::new(msg_text))],
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage {
+                    total_tokens: 15,
+                    output: 15,
+                    ..Usage::default()
+                },
+                stop_reason: StopReason::Stop,
+                error_message: None,
+                timestamp: 0,
+            };
+            let partial = AssistantMessage {
+                content: Vec::new(),
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage::default(),
+                stop_reason: StopReason::Stop,
+                error_message: None,
+                timestamp: 0,
+            };
+            return Ok(Box::pin(EventSequence {
+                events: vec![
+                    Some(StreamEvent::Start { partial }),
+                    Some(StreamEvent::Done {
+                        reason: StopReason::Stop,
+                        message: msg,
+                    }),
+                ],
+                index: 0,
+            }));
+        }
+
+        Err(Error::api("unexpected provider call"))
+    }
+}
