+// ===========================================================================
+// Agent: custom tool that returns Err (exercises execute_tool_without_hooks error wrapping)
+// ===========================================================================
+
+/// Custom tool that deliberately returns Err from execute().
+#[derive(Debug)]
+struct FailingTool;
+
+#[async_trait]
+impl Tool for FailingTool {
+    fn name(&self) -> &str {
+        "failing_tool"
+    }
+
+    fn description(&self) -> &str {
+        "A tool that always fails for testing"
+    }
+
+    fn input_schema(&self) -> serde_json::Value {
+        json!({
+            "type": "object",
+            "properties": {},
+            "required": []
+        })
+    }
+
+    async fn execute(
+        &self,
+        _tool_call_id: &str,
+        _input: serde_json::Value,
+        _on_update: Option<Box<dyn Fn(ToolUpdate) + Send + Sync>>,
+    ) -> std::result::Result<ToolOutput, pi::error::Error> {
+        Err(pi::error::Error::tool("failing_tool", "deliberate test failure"))
+    }
+}
+
+/// Provider that calls the FailingTool.
+#[derive(Debug)]
+struct FailingToolProvider {
+    stream_calls: AtomicUsize,
+}
+
+#[async_trait]
+#[allow(clippy::unnecessary_literal_bound)]
+impl Provider for FailingToolProvider {
+    fn name(&self) -> &str {
+        "failing-tool-provider"
+    }
+
+    fn api(&self) -> &str {
+        "failing-tool-api"
+    }
+
+    fn model_id(&self) -> &str {
+        "failing-tool-model"
+    }
+
+    async fn stream(
+        &self,
+        context: &Context,
+        _options: &StreamOptions,
+    ) -> Result<Pin<Box<dyn Stream<Item = Result<StreamEvent>> + Send>>> {
+        let call_index = self.stream_calls.fetch_add(1, Ordering::SeqCst);
+
+        if call_index == 0 {
+            let msg = AssistantMessage {
+                content: vec![ContentBlock::ToolCall(ToolCall {
+                    id: "fail-1".to_string(),
+                    name: "failing_tool".to_string(),
+                    arguments: json!({}),
+                    thought_signature: None,
+                })],
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage {
+                    total_tokens: 20,
+                    output: 20,
+                    ..Usage::default()
+                },
+                stop_reason: StopReason::ToolUse,
+                error_message: None,
+                timestamp: 0,
+            };
+            let partial = AssistantMessage {
+                content: Vec::new(),
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage::default(),
+                stop_reason: StopReason::Stop,
+                error_message: None,
+                timestamp: 0,
+            };
+            return Ok(Box::pin(EventSequence {
+                events: vec![
+                    Some(StreamEvent::Start { partial }),
+                    Some(StreamEvent::Done {
+                        reason: StopReason::ToolUse,
+                        message: msg,
+                    }),
+                ],
+                index: 0,
+            }));
+        }
+
+        if call_index == 1 {
+            let results: Vec<&ToolResultMessage> = context
+                .messages
+                .iter()
+                .filter_map(|m| match m {
+                    Message::ToolResult(r) => Some(r),
+                    _ => None,
+                })
+                .collect();
+
+            let msg_text = if let Some(result) = results.iter().find(|r| r.tool_call_id == "fail-1") {
+                format!(
+                    "fail_result: is_error={}, text={}",
+                    result.is_error,
+                    tool_result_text(result)
+                )
+            } else {
+                "fail_result: MISSING".to_string()
+            };
+
+            let msg = AssistantMessage {
+                content: vec![ContentBlock::Text(TextContent::new(msg_text))],
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage {
+                    total_tokens: 15,
+                    output: 15,
+                    ..Usage::default()
+                },
+                stop_reason: StopReason::Stop,
+                error_message: None,
+                timestamp: 0,
+            };
+            let partial = AssistantMessage {
+                content: Vec::new(),
+                api: self.api().to_string(),
+                provider: self.name().to_string(),
+                model: self.model_id().to_string(),
+                usage: Usage::default(),
+                stop_reason: StopReason::Stop,
+                error_message: None,
+                timestamp: 0,
+            };
+            return Ok(Box::pin(EventSequence {
+                events: vec![
+                    Some(StreamEvent::Start { partial }),
+                    Some(StreamEvent::Done {
+                        reason: StopReason::Stop,
+                        message: msg,
+                    }),
+                ],
+                index: 0,
+            }));
+        }
+
+        Err(Error::api("unexpected provider call"))
+    }
+}
