+/// Simple provider that always returns a stop response.
+#[derive(Debug)]
+struct SimpleStopProvider {
+    stream_calls: AtomicUsize,
+}
+
+#[async_trait]
+#[allow(clippy::unnecessary_literal_bound)]
+impl Provider for SimpleStopProvider {
+    fn name(&self) -> &str {
+        "simple-stop-provider"
+    }
+
+    fn api(&self) -> &str {
+        "simple-stop-api"
+    }
+
+    fn model_id(&self) -> &str {
+        "simple-stop-model"
+    }
+
+    async fn stream(
+        &self,
+        _context: &Context,
+        _options: &StreamOptions,
+    ) -> Result<Pin<Box<dyn Stream<Item = Result<StreamEvent>> + Send>>> {
+        let call_index = self.stream_calls.fetch_add(1, Ordering::SeqCst);
+        let msg = AssistantMessage {
+            content: vec![ContentBlock::Text(TextContent::new(format!(
+                "response #{call_index}"
+            )))],
+            api: self.api().to_string(),
+            provider: self.name().to_string(),
+            model: self.model_id().to_string(),
+            usage: Usage {
+                total_tokens: 10,
+                output: 10,
+                ..Usage::default()
+            },
+            stop_reason: StopReason::Stop,
+            error_message: None,
+            timestamp: 0,
+        };
+        let partial = AssistantMessage {
+            content: Vec::new(),
+            api: self.api().to_string(),
+            provider: self.name().to_string(),
+            model: self.model_id().to_string(),
+            usage: Usage::default(),
+            stop_reason: StopReason::Stop,
+            error_message: None,
+            timestamp: 0,
+        };
+        Ok(Box::pin(EventSequence {
+            events: vec![
+                Some(StreamEvent::Start { partial }),
+                Some(StreamEvent::Done {
+                    reason: StopReason::Stop,
+                    message: msg,
+                }),
+            ],
+            index: 0,
+        }))
+    }
+}
